#include <sys/ioctl.h>
#include <linux/binder.h>

int main() {
    int fd = open("/dev/binder", O_RDWR);
    if (fd < 0) return 1;

    struct binder_write_read bwr;
    struct binder_transaction_data tr;
    // 构造包含多个BINDER_TYPE_FD的transaction
    // 具体细节复杂，此处仅示意
    // 实际POC需精心计算偏移，使off-by-one覆盖关键结构
    printf("Triggering CVE-2019-2215...\n");
    // 发送ioctl
    ioctl(fd, BINDER_WRITE_READ, &bwr);
    close(fd);
    return 0;
