#include <stdio.h>
#include <string.h>

void vuln(char *input) {
    char buf[16];
    // 假设input长度为17，第17字节覆盖canary最低字节
    strcpy(buf, input);
}

int main() {
    char payload[17];
    memset(payload, 'A', 16);
    payload[16] = '\x00';  // 覆盖canary最低字节为0x00，保持原值
    vuln(payload);
    return 0;
}


