#include <stdio.h>
#include <string.h>
#include <stdlib.h>

void vulnerable(char *input) {
    char buf[64];
    int i;
    for(i = 0; i <= 64; i++) {  // off-by-one
        buf[i] = input[i];
    }
}

int main(int argc, char **argv) {
    if(argc < 2) return 1;
    vulnerable(argv[1]);
    return 0;
}


