#include <stdio.h>
#include <string.h>

void vulnerable(char *input) {
    char buf[64];
    // 故意使用strcpy而非strncpy，但假设input长度恰好64，strcpy会复制包括null终止符，共65字节
    // 实际上strcpy会复制直到遇到null，若input长度64则复制65字节（含null）
    // 但更典型的off-by-one是循环：for(i=0; i<=64; i++) buf[i]=input[i];
    // 这里用memcpy模拟：
    memcpy(buf, input, 65); // off-by-one: 复制65字节到64字节缓冲区
}

int main(int argc, char **argv) {
    if (argc < 2) return 1;
    vulnerable(argv[1]);
    return 0;
}

编译时关闭栈保护：`gcc -fno-stack-protector -z execstack -o vuln vuln.c`

