    char *src = "AAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAA"; // 65字节
    memcpy(buf, src, 65); // off-by-one: 复制65字节到64字节缓冲区
    printf("%s\n", buf);
}

int main() {
    vuln();
    return 0;
}


