// heap_offbyone.c
#include <stdio.h>
#include <stdlib.h>
#include <string.h>

int main() {
    char *a = malloc(0x100);
    char *b = malloc(0x200);
    char *c = malloc(0x100);

    // 模拟off-by-one：向a写入0x101字节，覆盖b的size最低字节
    memset(a, 'A', 0x101);

    free(b); // 触发异常合并
    printf("Done\n");
    return 0;
}


