    // 更精确：原b的size为0x91（PREV_INUSE置位），覆盖最低字节为0x91不变？需要改为0xa1
    // 这里简化：假设我们覆盖为0xa1

    char *d = malloc(0x98); // 从b中分割出0xa0大小，导致与c重叠

    // 现在d和c重叠，可以通过d修改c的指针
    strcpy(d, "overlap");
    printf("c: %s\n", c); // 输出overlap
