    char buf[8];
    // 假设buf在栈上，canary在buf之后
    strcpy(buf, input); // off-by-one
    printf("Buffer: %s\n", buf);
}

int main() {
    char payload[] = "AAAAAAAA\x00"; // 9个字节，最后一个0x00覆盖canary最低字节
    vulnerable(payload);
    return 0;
}

注意：实际布局需要调试确定。

