#include <stdio.h>
#include <string.h>

void vulnerable(char *input) {
    char buf[64];
    int is_admin = 0;  // fence变量
    // 故意使用 <= 导致off-by-one
    for (int i = 0; i <= 64; i++) {
        buf[i] = input[i];
    }
    if (is_admin) {
        printf("Access granted!\n");
    } else {
        printf("Access denied.\n");
    }
}

int main() {
    char payload[65];
    memset(payload, 'A', 64);
    payload[64] = 0x01;  // 覆盖is_admin最低字节为1
    vulnerable(payload);
    return 0;
}


