#include <stdio.h>
#include <stdlib.h>
#include <string.h>

// 模拟有漏洞的b64decode
int b64decode_vuln(const char *in, unsigned char *out, int outlen) {
    int len = strlen(in);
    int olen = (len * 3) / 4;  // 计算输出长度
    if (olen > outlen) return -1;
    int i, j = 0;
    for (i = 0; i < len; i += 4) {
        // 解码逻辑（简化）
        out[j++] = 0;  // 实际解码值
        // 漏洞：当输入长度不是4的倍数时，循环可能多写一个字节
    }
    // 由于olen计算可能偏大，但循环中j可能超过olen？实际漏洞更复杂
    return j;
}

int main() {
    char *buf = malloc(64);
    char input[] = "AAAA";  // 特制输入
    b64decode_vuln(input, buf, 64);
    free(buf);
    return 0;
}

实际利用需要结合堆布局，这里仅展示概念。

