        buf[i] = input[i];
        if (input[i] == '\0') break;
    }
    // 后续操作使用len进行拷贝
    char tmp[128];
    // 假设程序有第二次写入，基于len
    // 例如：read(0, buf, len); 此时len已被修改
}

