        buf[i] = input[i];
    }
}

int main() {
    char payload[9] = "AAAAAAAA"; // 8个A填充buf，第9个字节覆盖EBP最低位
    // 实际利用需要精心构造payload，此处仅为演示
    vulnerable(payload);
    return 0;
}


