#include <string.h>

void vuln(char *input) {
    char buf[8];
    for (int i = 0; i <= 8; i++) {
        buf[i] = input[i];
    }
}

int main() {
    char payload[9];
    // 构造payload：前8字节填充buf，第9字节覆盖EBP低字节
    // 实际利用需要知道栈地址，这里仅演示
    memset(payload, 'A', 8);
    payload[8] = 0x00; // 假设原始EBP低字节为0x??，改为0x00
    vuln(payload);
    return 0;
