#include <stdio.h>
#include <stdlib.h>
#include <string.h>

int main() {
    char *a = malloc(0x100);
    char *b = malloc(0x80);
    char *c = malloc(0x80); // 防止与top chunk合并

    // 触发Off-by-one：写入0x101字节，覆盖b的size
    memset(a, 'A', 0x100);
    a[0x100] = 0x91; // 将b的size从0x81改为0x91

    free(b); // 释放b，此时b的size为0x90，free会将其放入unsorted bin

    // 重新分配0x90大小的chunk，会从unsorted bin中分割，得到b的地址
    char *d = malloc(0x88); // 实际分配0x90大小（含chunk头）
    // 现在d与c重叠，可以通过d修改c的数据

    // 进一步利用：修改c的fd/bk指针进行unlink攻击
    // ...
    return 0;
}


