#include <stdio.h>
#include <string.h>

void vulnerable(char *input) {
    char buf[64];
    int i;
    // Off-by-one: loop condition i <= 64, writes 65 bytes
    for (i = 0; i <= 64; i++) {
        buf[i] = input[i];
    }
}

int main(int argc, char **argv) {
    if (argc < 2) return 1;
    vulnerable(argv[1]);
    return 0;
}


